  (DATE '2024-12-15'),
  (DATE '2025-01-05'),
  (DATE '2025-01-20'),
  (DATE '2025-02-14'),
  (DATE '2025-03-10'),
  (DATE '2025-03-31'),
  (DATE '2025-04-05'),
  (DATE '2025-06-01');
SELECT * FROM orders WHERE order_date BETWEEN '2025-01-01' AND '2025-03-31';

SELECT c.customer_id, c.name FROM customers c
LEFT JOIN orders o ON c.customer_id = o.customer_id
WHERE o.order_id IS NULL;

SELECT name, COALESCE(bonus, 0) AS bonus_amount
FROM employees
ORDER BY name;

SELECT year, revenue,
  100.0*(revenue - LAG(revenue) OVER (ORDER BY year))/NULLIF(LAG(revenue) OVER (ORDER BY year),0) AS yoy_pct
FROM annual_revenue;

SELECT sale_date, amount,
  SUM(amount) OVER (ORDER BY sale_date) AS cumulative
FROM sales;

WITH dept_avg AS (SELECT dept_id, AVG(salary) AS avg_sal FROM employees GROUP BY dept_id)
SELECT e.emp_id, e.salary, d.avg_sal, e.salary - d.avg_sal AS diff
FROM employees e JOIN dept_avg d ON e.dept_id = d.dept_id;

SELECT metric_date, value,
  AVG(value) OVER (ORDER BY metric_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS ma7
FROM metrics;

SELECT 100.0 * COUNT(DISTINCT CASE WHEN later.student_id IS NOT NULL THEN e.student_id END) / NULLIF(COUNT(DISTINCT e.student_id), 0) AS reenroll_rate
FROM enrollments e
LEFT JOIN enrollments later ON e.student_id = later.student_id AND later.term > e.term;

SELECT c.customer_id, c.name, COUNT(o.order_id) AS orders, SUM(o.amount) AS total
FROM customers c LEFT JOIN orders o ON c.customer_id = o.customer_id
GROUP BY c.customer_id, c.name;

SELECT post_id,
  REGEXP_REPLACE(content, '\\b(spam|abuse|hate)\\b', '***', 1, 0, 'i') AS cleaned
FROM posts;

SELECT * FROM (
  SELECT *, ROW_NUMBER() OVER (PARTITION BY product_name, sku ORDER BY updated_at DESC) AS rn
  FROM products
