        while parent[x] != x: parent[x] = parent[parent[x]]; x = parent[x]
        return x
    for a, b in edges:
        ra, rb = find(a), find(b)
        if ra != rb: parent[ra] = rb
    return len({find(i) for i in range(n)})

import heapq

def minCostConnectPoints(points):
    n = len(points); seen = {0}; total = 0
    h = [(abs(points[0][0] - points[j][0]) + abs(points[0][1] - points[j][1]), j) for j in range(1, n)]
    heapq.heapify(h)
    while len(seen) < n:
        d, u = heapq.heappop(h)
        if u in seen: continue
        seen.add(u); total += d
        for v in range(n):
            if v not in seen:
                heapq.heappush(h, (abs(points[u][0]-points[v][0]) + abs(points[u][1]-points[v][1]), v))
    return total

import heapq
from collections import defaultdict

def networkDelayTime(times, n, k):
    g = defaultdict(list)
    for u, v, w in times: g[u].append((v, w))
    dist = {}; pq = [(0, k)]
    while pq:
        d, u = heapq.heappop(pq)
        if u in dist: continue
        dist[u] = d
        for v, w in g[u]:
            if v not in dist: heapq.heappush(pq, (d + w, v))
    return max(dist.values()) if len(dist) == n else -1

from collections import defaultdict, deque

def findCheapestPrice(n, flights, src, dst, k):
    g = defaultdict(list)
    for u, v, w in flights: g[u].append((v, w))
    INF = float('inf'); cost = [INF] * n; cost[src] = 0
    q = deque([(src, 0, 0)])
    while q:
        u, c, stops = q.popleft()
        if stops > k: continue
        for v, w in g[u]:
            if c + w < cost[v]:
                cost[v] = c + w; q.append((v, c + w, stops + 1))
    return -1 if cost[dst] == INF else cost[dst]

def canJump(nums):
    reach = 0
    for i, n in enumerate(nums):
        if i > reach: return False
        reach = max(reach, i + n)
    return True

def jump(nums):
    jumps = end = far = 0
    for i in range(len(nums) - 1):
        far = max(far, i + nums[i])
        if i == end: jumps += 1; end = far
    return jumps

def mergeTriplets(triplets, target):
    have = [False] * 3
    for t in triplets:
        if all(t[i] <= target[i] for i in range(3)):
            for i in range(3):
                if t[i] == target[i]: have[i] = True
    return all(have)

def partitionLabels(s):
    last = {c: i for i, c in enumerate(s)}
    res, start, end = [], 0, 0
    for i, c in enumerate(s):
        end = max(end, last[c])
        if i == end: res.append(end - start + 1); start = i + 1
    return res

import heapq

def minMeetingRooms(intervals):
    intervals.sort(key=lambda x: x[0])
    h = []
    for s, e in intervals:
        if h and h[0] <= s: heapq.heappop(h)
        heapq.heappush(h, e)
    return len(h)

