import os, urllib.request, hashlib
from concurrent.futures import ThreadPoolExecutor, as_completed
from pathlib import Path

OUT = Path('./downloads')
OUT.mkdir(exist_ok=True)

def local_path(url):
    # Stable filename from URL hash to avoid collisions / weird chars
    h = hashlib.sha1(url.encode()).hexdigest()[:12]
    ext = os.path.splitext(url.split('?')[0])[1] or '.bin'
    return OUT / f"{h}{ext}"

def download(url):
    dst = local_path(url)
    if dst.exists() and dst.stat().st_size > 0:
        return (url, 'skipped')
    try:
        urllib.request.urlretrieve(url, dst)
        return (url, 'ok')
    except Exception as e:
        if dst.exists(): dst.unlink()      # remove partial
        return (url, f'error: {e}')

urls = [line.strip() for line in open('urls.txt') if line.strip()]
with ThreadPoolExecutor(max_workers=8) as ex:
    futures = [ex.submit(download, u) for u in urls]
    for f in as_completed(futures):
        url, status = f.result()
        print(f"{status:8s} {url}")

# I/O-bound work (HTTP) → threads, not processes. For CPU-bound work
# (image resize, parsing huge files) use ProcessPoolExecutor instead.

import hashlib
from pathlib import Path
from collections import defaultdict

def file_hash(path, chunk=1 << 20):           # 1 MiB chunks
    h = hashlib.sha256()
    with open(path, 'rb') as f:
        while True:
            data = f.read(chunk)
            if not data: break
            h.update(data)
    return h.hexdigest()

groups = defaultdict(list)
for p in Path('/photos').rglob('*'):
    if p.is_file():
        groups[file_hash(p)].append(p)

for digest, paths in groups.items():
    if len(paths) > 1:
        print(f"\n{digest[:12]}  ({len(paths)} copies)")
        for p in paths:
            print(f"  {p}")

# Optimization for huge libraries: bucket by file SIZE first; only hash
# files whose sizes collide. Most files have unique sizes, so you skip
# 99% of hashing work.

import os, re, time

PATTERN = re.compile(r'ERROR|FATAL|Traceback')

def tail(path, poll=0.5):
    f = open(path)
    f.seek(0, 2)                              # jump to end of file
    inode = os.fstat(f.fileno()).st_ino
    while True:
        line = f.readline()
        if line:
            if PATTERN.search(line):
                yield line.rstrip()
            continue
        time.sleep(poll)
        # Detect rotation: the file at this path now has a different inode
        try:
            new_inode = os.stat(path).st_ino
        except FileNotFoundError:
            continue
        if new_inode != inode:
            f.close()
            f = open(path)
            inode = new_inode
            print('--- log rotated, reopened ---')

if __name__ == '__main__':
    for hit in tail('/var/log/app.log'):
        print(hit)

