def sliding_window(iterable, n):
    if n <= 0:
        raise ValueError('n must be positive')
    it = iter(iterable)
    window = deque(maxlen=n)
    for x in it:
        window.append(x)
        if len(window) == n:
            yield tuple(window)

from functools import wraps

class RateLimit:
    def __init__(self, calls_per_window):
        self.limit = calls_per_window
        self.count = 0

    def reset(self):
        self.count = 0

    def __call__(self, fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            if self.count >= self.limit:
                raise RuntimeError('rate limited')
            self.count += 1
            return fn(*args, **kwargs)
        wrapper.reset = self.reset
        return wrapper

def flatten(nested):
    for item in nested:
        if isinstance(item, (str, bytes)):
            yield item
        else:
            try:
                iter(item)
            except TypeError:
                yield item
            else:
                yield from flatten(item)

def merge_intervals(intervals):
    if not intervals:
        return []
    ordered = sorted(intervals, key=lambda iv: iv[0])
    merged = [list(ordered[0])]
    for start, end in ordered[1:]:
        if start <= merged[-1][1]:
            merged[-1][1] = max(merged[-1][1], end)
        else:
            merged.append([start, end])
    return merged

class Trie:
    _END = '$'
    def __init__(self):
        self.root = {}
    def insert(self, word):
        node = self.root
        for ch in word:
            node = node.setdefault(ch, {})
        node[self._END] = True
    def _walk(self, key):
        node = self.root
        for ch in key:
            if ch not in node:
                return None
            node = node[ch]
        return node
    def contains(self, word):
        node = self._walk(word)
        return node is not None and node.get(self._END, False)
    def starts_with(self, prefix):
        return self._walk(prefix) is not None

from urllib.parse import parse_qsl

def parse_query_string(qs):
    result = {}
    for k, v in parse_qsl(qs, keep_blank_values=True):
        result.setdefault(k, []).append(v)
    return result

def group_consecutive(iterable, key=None):
    if key is None:
        key = lambda x: x
    it = iter(iterable)
    try:
        first = next(it)
    except StopIteration:
        return
    current_key = key(first)
    bucket = [first]
    for item in it:
        k = key(item)
        if k == current_key:
            bucket.append(item)
        else:
            yield (current_key, bucket)
            current_key = k
            bucket = [item]
    yield (current_key, bucket)

import re

_LOG_RE = re.compile(
    r'^(?P<ip>\S+)\s+\S+\s+\S+\s+\[[^\]]+\]\s+'
    r'"(?P<method>[A-Z]+)\s+(?P<path>\S+)\s+HTTP/[\d.]+"\s+'
    r'(?P<status>\d+)\s+(?P<bytes>\d+)'
)

def parse_access_log(text):
    out = []
    for line in text.splitlines():
        if not line.strip():
            continue
        m = _LOG_RE.match(line)
        if m:
            out.append({
                'ip': m.group('ip'),
                'method': m.group('method'),
                'path': m.group('path'),
                'status': int(m.group('status')),
                'bytes': int(m.group('bytes')),
            })
    return out

