def diff_dicts(old, new):
    old_keys = set(old)
    new_keys = set(new)
    return {
        'added': {k: new[k] for k in new_keys - old_keys},
        'removed': {k: old[k] for k in old_keys - new_keys},
        'changed': {k: (old[k], new[k]) for k in old_keys & new_keys if old[k] != new[k]},
    }

