from collections import deque

class MovingAverage:
    def __init__(self, window):
        if window <= 0:
            raise ValueError('window must be positive')
        self.window = window
        self.q = deque()
        self.total = 0.0
    def add(self, x):
        self.q.append(x)
        self.total += x
        if len(self.q) > self.window:
            self.total -= self.q.popleft()
    def value(self):
        if not self.q:
            return 0.0
        return self.total / len(self.q)

def percentile(values, p):
    if not values:
        raise ValueError('empty input')
    if not (0 <= p <= 100):
        raise ValueError('p must be in [0, 100]')
    s = sorted(values)
    n = len(s)
    idx = (n - 1) * p / 100.0
    lo = int(idx)
    hi = lo + 1
    if hi >= n:
        return float(s[lo])
    frac = idx - lo
    return s[lo] + (s[hi] - s[lo]) * frac

import heapq

def top_k_largest(stream, k):
    if k <= 0:
        return []
    heap = []
    for x in stream:
        if len(heap) < k:
            heapq.heappush(heap, x)
        elif x > heap[0]:
            heapq.heapreplace(heap, x)
    return sorted(heap, reverse=True)

import heapq

def merge_sorted(*iters):
    # heap entries: (value, source_index, iterator) — source_index breaks ties without comparing iterators
    heap = []
    for i, it in enumerate(iters):
        it = iter(it)
        try:
            first = next(it)
        except StopIteration:
            continue
        heap.append((first, i, it))
    heapq.heapify(heap)
    while heap:
        val, i, it = heapq.heappop(heap)
        yield val
        try:
            nxt = next(it)
            heapq.heappush(heap, (nxt, i, it))
        except StopIteration:
            pass

def is_valid_card(number):
    s = str(number)
    digits = [int(c) for c in s if c.isdigit()]
    if not (13 <= len(digits) <= 19):
        return False
    total = 0
    # Walk right-to-left; double every 2nd digit (i.e., positions 1,3,5 from the right)
    for i, d in enumerate(reversed(digits)):
        if i % 2 == 1:
            d *= 2
            if d >= 10:
                d -= 9
        total += d
    return total % 10 == 0

from collections import defaultdict

def sessionize(events, idle_gap_s=1800):
    by_user = defaultdict(list)
    for e in events:
        by_user[e['user']].append(e)
    sessions = []
    for user, evs in by_user.items():
        evs.sort(key=lambda e: e['ts'])
        cur = None
        for e in evs:
            if cur is None or e['ts'] - cur['end'] > idle_gap_s:
                if cur is not None:
                    sessions.append(cur)
                cur = {'user': user, 'start': e['ts'], 'end': e['ts'], 'events': [e]}
            else:
                cur['end'] = e['ts']
                cur['events'].append(e)
        if cur is not None:
            sessions.append(cur)
    sessions.sort(key=lambda s: (s['user'], s['start']))
    return sessions

from collections import defaultdict

def funnel(events, steps):
    if not steps:
        return []
    by_user = defaultdict(list)
    for e in events:
        by_user[e['user']].append(e)
    counts = [0] * len(steps)
    for evs in by_user.values():
        evs.sort(key=lambda e: e['ts'])
        step_idx = 0
        for e in evs:
            if step_idx >= len(steps):
                break
            if e['event'] == steps[step_idx]:
                counts[step_idx] += 1
                step_idx += 1
    return counts

