from datetime import date, timedelta

def missing_dates(dates):
    if not dates:
        return []
    seen = {date.fromisoformat(d) for d in dates}
    lo, hi = min(seen), max(seen)
    out = []
    d = lo + timedelta(days=1)
    while d < hi:
        if d not in seen:
            out.append(d.isoformat())
        d += timedelta(days=1)
    return out

