def business_days(start, end, holidays=None):
    if end <= start:
        return 0
    holiday_set = set(holidays) if holidays else set()
    count = 0
    d = start
    while d < end:
        if d.weekday() < 5 and d not in holiday_set:
            count += 1
        d += timedelta(days=1)
    return count

def humanize_ago(seconds_ago):
    s = int(seconds_ago)
    if s < 60:
        return 'just now'
    if s < 3600:
        n = s // 60
        return f'{n} minute{"s" if n != 1 else ""} ago'
    if s < 86400:
        n = s // 3600
        return f'{n} hour{"s" if n != 1 else ""} ago'
    if s < 2592000:
        n = s // 86400
        return f'{n} day{"s" if n != 1 else ""} ago'
    if s < 31536000:
        n = s // 2592000
        return f'{n} month{"s" if n != 1 else ""} ago'
    n = s // 31536000
    return f'{n} year{"s" if n != 1 else ""} ago'

