from functools import wraps

def with_retry(attempts=3, initial_delay=0.01, factor=2, exceptions=(Exception,), sleeper=time.sleep):
    def deco(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            delay = initial_delay
            for i in range(attempts):
                try:
                    return fn(*args, **kwargs)
                except exceptions:
                    if i == attempts - 1:
                        raise
                    sleeper(delay)
                    delay *= factor
        return wrapper
    return deco

from collections import OrderedDict
from functools import wraps

def memoize(maxsize):
    def deco(fn):
        cache = OrderedDict()
        stats = {'hits': 0, 'misses': 0}
        @wraps(fn)
        def wrapper(*args):
            if args in cache:
                stats['hits'] += 1
                return cache[args]
            stats['misses'] += 1
            val = fn(*args)
            cache[args] = val
            if len(cache) > maxsize:
                cache.popitem(last=False)  # FIFO: evict the oldest
            return val
        wrapper.cache_info = lambda: {'hits': stats['hits'], 'misses': stats['misses'], 'currsize': len(cache)}
        return wrapper
    return deco

import time

class TTLCache:
    def __init__(self, ttl_seconds, clock=time.time):
        self.ttl = ttl_seconds
        self.clock = clock
        self._store = {}
    def set(self, key, value):
        self._store[key] = (value, self.clock())
    def get(self, key):
        if key not in self._store:
            return None
        value, ts = self._store[key]
        if self.clock() - ts > self.ttl:
            del self._store[key]
            return None
        return value
    def __contains__(self, key):
        return self.get(key) is not None

import time

class TokenBucket:
    def __init__(self, rate, capacity, clock=time.monotonic):
        self.rate = rate
        self.capacity = capacity
        self.clock = clock
        self.tokens = float(capacity)
        self.last = clock()
    def _refill(self):
        now = self.clock()
        elapsed = now - self.last
        if elapsed > 0:
            self.tokens = min(self.capacity, self.tokens + elapsed * self.rate)
            self.last = now
    def try_acquire(self, n=1):
        self._refill()
        if self.tokens >= n:
            self.tokens -= n
            return True
        return False

import queue
import threading

def process_items(items, worker_fn, num_workers=4):
    if not items:
        return []
    q = queue.Queue()
    results = [None] * len(items)
    for i, item in enumerate(items):
        q.put((i, item))
    SENTINEL = object()
    for _ in range(num_workers):
        q.put(SENTINEL)
    def worker():
        while True:
            task = q.get()
            if task is SENTINEL:
                q.task_done()
                return
            i, item = task
            results[i] = worker_fn(item)
            q.task_done()
    threads = [threading.Thread(target=worker) for _ in range(num_workers)]
    for t in threads:
        t.start()
    for t in threads:
        t.join()
    return results

class BloomFilter:
    def __init__(self, size, hashes):
        self.size = size
        self.k = hashes
        self.bits = bytearray(size)  # bit-per-byte for simplicity
    def _positions(self, item):
        # Mix a salt into the hash so we get k distinct positions deterministically
        for i in range(self.k):
            h = hash((i, item)) % self.size
            yield h
    def add(self, item):
        for p in self._positions(item):
            self.bits[p] = 1
    def __contains__(self, item):
        return all(self.bits[p] for p in self._positions(item))

