def parse_ini(text):
    sections = {'DEFAULT': {}}
    current = 'DEFAULT'
    for line in text.splitlines():
        line = line.strip()
        if not line or line.startswith(';') or line.startswith('#'):
            continue
        if line.startswith('[') and line.endswith(']'):
            current = line[1:-1].strip()
            sections.setdefault(current, {})
            continue
        if '=' in line:
            k, _, v = line.partition('=')
            sections[current][k.strip()] = v.strip()
    return sections

import hashlib

def anonymize(record, pii_fields, salt=''):
    pii = set(pii_fields)
    out = {}
    for k, v in record.items():
        if k in pii:
            out[k] = hashlib.sha256((salt + str(v)).encode('utf-8')).hexdigest()
        else:
            out[k] = v
    return out

def schema_diff(old, new):
    def schema(records):
        types = {}
        for r in records:
            for k, v in r.items():
                if k not in types and v is not None:
                    types[k] = type(v).__name__
            for k in r:
                types.setdefault(k, type(None).__name__)
        return types
    old_s = schema(old)
    new_s = schema(new)
    added = set(new_s) - set(old_s)
    removed = set(old_s) - set(new_s)
    common = set(old_s) & set(new_s)
    type_changed = {c: (old_s[c], new_s[c]) for c in common if old_s[c] != new_s[c]}
    return {'added': added, 'removed': removed, 'type_changed': type_changed}

