def dedupe_latest(messages):
    # First pass: find the winning record per id
    winners = {}
    for m in messages:
        mid = m['id']
        if mid not in winners or m['ts'] >= winners[mid]['ts']:
            winners[mid] = m
    # Second pass: emit in first-appearance order
    order = []
    seen = set()
    for m in messages:
        if m['id'] not in seen:
            seen.add(m['id'])
            order.append(m['id'])
    return [winners[k] for k in order]

