def most_common_manual(items, n=None):
    counts = {}
    order = {}
    for i, x in enumerate(items):
        if x not in counts:
            counts[x] = 0
            order[x] = i
        counts[x] += 1
    # Sort by (-count, first_seen_index)
    sorted_items = sorted(counts.items(), key=lambda kv: (-kv[1], order[kv[0]]))
    return sorted_items if n is None else sorted_items[:n]

def first_duplicates(stream):
    seen_once = set()
    seen_twice = set()
    for x in stream:
        if x in seen_twice:
            continue
        if x in seen_once:
            seen_twice.add(x)
            yield x
        else:
            seen_once.add(x)

