class _Node:
    __slots__ = ('children', 'weight')
    def __init__(self):
        self.children = {}
        self.weight = 0  # 0 means not a word-end

class Autocomplete:
    def __init__(self):
        self.root = _Node()
    def add(self, word, weight=1):
        node = self.root
        for ch in word:
            node = node.children.setdefault(ch, _Node())
        node.weight += weight
    def _collect(self, node, prefix, out):
        if node.weight > 0:
            out.append((prefix, node.weight))
        for ch, child in node.children.items():
            self._collect(child, prefix + ch, out)
    def suggest(self, prefix, k=5):
        node = self.root
        for ch in prefix:
            if ch not in node.children:
                return []
            node = node.children[ch]
        candidates = []
        self._collect(node, prefix, candidates)
        candidates.sort(key=lambda wp: (-wp[1], wp[0]))
        return [w for w, _ in candidates[:k]]

