import numpy as np

def zscore(arr):
    a = np.asarray(arr, dtype=float)
    if a.size == 0:
        raise ValueError('empty array')
    mean = a.mean()
    std = a.std(ddof=0)
    if std == 0:
        raise ValueError('zero variance')
    return (a - mean) / std

def reservoir_sample(stream, k, rng):
    reservoir = []
    for i, x in enumerate(stream):
        if i < k:
            reservoir.append(x)
        else:
            j = rng.randint(0, i)  # inclusive
            if j < k:
                reservoir[j] = x
    return reservoir

def is_valid_isbn10(s):
    if not isinstance(s, str):
        return False
    cleaned = s.replace('-', '').replace(' ', '').upper()
    if len(cleaned) != 10:
        return False
    if not (cleaned[:9].isdigit() and (cleaned[9].isdigit() or cleaned[9] == 'X')):
        return False
    total = 0
    for i, c in enumerate(cleaned):
        digit = 10 if c == 'X' else int(c)
        total += digit * (10 - i)
    return total % 11 == 0

