def merge_periods(periods):
    if not periods:
        return []
    sorted_p = sorted(periods, key=lambda p: p[0])
    merged = [sorted_p[0]]
    for s, e in sorted_p[1:]:
        last_s, last_e = merged[-1]
        if s <= last_e + timedelta(days=1):
            merged[-1] = (last_s, max(last_e, e))
        else:
            merged.append((s, e))
    return merged

