import queue
import threading

def bounded_pipeline(items, transform, max_inflight=4):
    items = list(items)
    n = len(items)
    if n == 0:
        return []
    results = [None] * n
    work = queue.Queue(maxsize=max_inflight)
    SENTINEL = object()
    def worker():
        while True:
            task = work.get()
            if task is SENTINEL:
                work.task_done()
                return
            i, item = task
            results[i] = transform(item)
            work.task_done()
    threads = [threading.Thread(target=worker) for _ in range(max_inflight)]
    for t in threads:
        t.start()
    for i, item in enumerate(items):
        work.put((i, item))  # blocks if queue is full -> bounds in-flight work
    for _ in range(max_inflight):
        work.put(SENTINEL)
    for t in threads:
        t.join()
    return results

