import heapq
from collections import defaultdict

def topo_sort(graph):
    # Build reverse graph: dep -> dependents, plus in-degree (= # unsatisfied deps)
    dependents = defaultdict(list)
    in_degree = {}
    nodes = set(graph.keys())
    for node, deps in graph.items():
        in_degree.setdefault(node, 0)
        for d in deps:
            dependents[d].append(node)
            in_degree[node] = in_degree.get(node, 0) + 1
            nodes.add(d)
            in_degree.setdefault(d, 0)
    # Recompute in_degree cleanly so deps not in graph keys are 0
    in_degree = {n: 0 for n in nodes}
    for node, deps in graph.items():
        in_degree[node] = len(set(deps))
    ready = [n for n in nodes if in_degree[n] == 0]
    heapq.heapify(ready)
    out = []
    while ready:
        n = heapq.heappop(ready)
        out.append(n)
        for m in dependents[n]:
            in_degree[m] -= 1
            if in_degree[m] == 0:
                heapq.heappush(ready, m)
    if len(out) != len(nodes):
        raise ValueError('cycle detected')
    return out

def rle_decode(s):
    out = []
    i = 0
    n = len(s)
    while i < n:
        j = i
        while j < n and s[j].isdigit():
            j += 1
        if j == i or j == n:
            raise ValueError(f'malformed RLE at position {i}')
        count = int(s[i:j])
        out.append(s[j] * count)
        i = j + 1
    return ''.join(out)

from collections import deque

def round_robin(*iters):
    active = deque(iter(it) for it in iters)
    while active:
        it = active.popleft()
        try:
            yield next(it)
        except StopIteration:
            continue  # don't re-append, this iterator is done
        active.append(it)

def is_balanced(s):
    pairs = {')': '(', ']': '[', '}': '{'}
    openers = set('([{')
    stack = []
    for c in s:
        if c in openers:
            stack.append(c)
        elif c in pairs:
            if not stack or stack.pop() != pairs[c]:
                return False
    return not stack

