def remove_stopwords(text, stopwords):
    stop = {w.lower() for w in stopwords}
    def repl(m):
        return '' if m.group(0).lower() in stop else m.group(0)
    s = re.sub(r'[A-Za-z]+', repl, text)
    # Collapse whitespace
    s = re.sub(r'\s+', ' ', s)
    return s.strip()

from collections import deque

def shortest_path(graph, start, end):
    if start == end:
        return [start]
    if start not in graph:
        return []
    visited = {start}
    parent = {start: None}
    q = deque([start])
    while q:
        node = q.popleft()
        for nb in graph.get(node, []):
            if nb in visited:
                continue
            visited.add(nb)
            parent[nb] = node
            if nb == end:
                # Reconstruct path
                path = [end]
                while parent[path[-1]] is not None:
                    path.append(parent[path[-1]])
                return list(reversed(path))
            q.append(nb)
    return []

def cron_matches(cron, dt):
    fields = cron.split()
    if len(fields) != 5:
        raise ValueError('cron must have 5 fields')
    def match(field, value):
        if field == '*':
            return True
        return value in {int(x) for x in field.split(',')}
    minute, hour, day, month, dow = fields
    return (match(minute, dt.minute) and match(hour, dt.hour) and
            match(day, dt.day) and match(month, dt.month) and
            match(dow, dt.weekday()))

import ipaddress

def classify_ip(s):
    try:
        addr = ipaddress.ip_address(s)
    except (ValueError, TypeError):
        return 'invalid'
    return 'ipv4' if isinstance(addr, ipaddress.IPv4Address) else 'ipv6'

def parallel_batches(graph):
    # Make sure every node mentioned (even as a dep) is a key
    all_nodes = set(graph.keys())
    for deps in graph.values():
        all_nodes.update(deps)
    in_deg = {n: 0 for n in all_nodes}
    children = {n: set() for n in all_nodes}
    for node, deps in graph.items():
        unique_deps = set(deps)
        in_deg[node] = len(unique_deps)
        for d in unique_deps:
            children[d].add(node)
    batches = []
    remaining = set(all_nodes)
    while remaining:
        ready = sorted([n for n in remaining if in_deg[n] == 0])
        if not ready:
            raise ValueError('cycle detected')
        batches.append(ready)
        for n in ready:
            for c in children[n]:
                in_deg[c] -= 1
            remaining.discard(n)
    return batches

