def first_missing_positive(nums):
    n = len(nums)
    if n == 0:
        return 1
    # Place each value v (1 <= v <= n) at index v-1 via cyclic swaps.
    i = 0
    while i < n:
        v = nums[i]
        if 1 <= v <= n and nums[v - 1] != v:
            nums[i], nums[v - 1] = nums[v - 1], nums[i]
        else:
            i += 1
    # First index where nums[i] != i+1 is the answer.
    for i in range(n):
        if nums[i] != i + 1:
            return i + 1
    return n + 1

from collections import Counter

def first_unique(items):
    items = list(items)
    counts = Counter(items)
    for x in items:
        if counts[x] == 1:
            return x
    return None

def median_two_sorted(a, b):
    m, n = len(a), len(b)
    total = m + n
    # We only need to walk until index total // 2 in the merged stream.
    target = total // 2
    i = j = 0
    prev = curr = 0
    for _ in range(target + 1):
        prev = curr
        if i < m and (j >= n or a[i] <= b[j]):
            curr = a[i]
            i += 1
        else:
            curr = b[j]
            j += 1
    if total % 2 == 1:
        return float(curr)
    return (prev + curr) / 2

def daily_temperatures(temps):
    n = len(temps)
    out = [0] * n
    stack = []  # holds indices with strictly decreasing temps
    for i, t in enumerate(temps):
        while stack and temps[stack[-1]] < t:
            j = stack.pop()
            out[j] = i - j
        stack.append(i)
    return out

def subset_sum_exists(nums, target):
    if target < 0:
        return False
    reachable = {0}
    for n in nums:
        if n < 0:
            continue  # outside the stated domain; ignore
        new_reach = set(reachable)
        for r in reachable:
            s = r + n
            if s == target:
                return True
            if s < target:
                new_reach.add(s)
        reachable = new_reach
    return target in reachable

def coin_change_min(coins, amount):
    if amount == 0:
        return 0
    INF = amount + 1
    dp = [INF] * (amount + 1)
    dp[0] = 0
    for x in range(1, amount + 1):
        for c in coins:
            if c <= x and dp[x - c] + 1 < dp[x]:
                dp[x] = dp[x - c] + 1
    return dp[amount] if dp[amount] != INF else -1

def int_to_roman(n):
    if not (1 <= n <= 3999):
        raise ValueError(f'out of range: {n!r}')
    pairs = [
        (1000, 'M'), (900, 'CM'),
        (500, 'D'),  (400, 'CD'),
        (100, 'C'),  (90, 'XC'),
        (50, 'L'),   (40, 'XL'),
        (10, 'X'),   (9, 'IX'),
        (5, 'V'),    (4, 'IV'),
        (1, 'I'),
    ]
    out = []
    for val, sym in pairs:
        while n >= val:
            out.append(sym)
            n -= val
    return ''.join(out)

def roman_to_int(s):
    values = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    total = 0
    prev = 0
    # Walk right-to-left: if current symbol is smaller than the one to its right, subtract it.
    for ch in reversed(s):
        v = values[ch]
        if v < prev:
            total -= v
        else:
            total += v
        prev = v
    return total

def eval_basic_expr(expr):
    s = expr.replace(' ', '')
    if not s:
        return 0
    stack = []
    num = 0
    op = '+'
    i = 0
    n = len(s)
    while i < n:
        ch = s[i]
        if ch.isdigit():
            num = num * 10 + int(ch)
        if (not ch.isdigit()) or i == n - 1:
            if op == '+':
                stack.append(num)
            elif op == '-':
                stack.append(-num)
            elif op == '*':
                stack.append(stack.pop() * num)
            elif op == '/':
                top = stack.pop()
                # Truncate toward zero (not Python's floor for negatives)
                stack.append(int(top / num))
            op = ch
            num = 0
        i += 1
    return sum(stack)

from collections import defaultdict

class EventBus:
    def __init__(self):
        self._subs = defaultdict(list)

    def subscribe(self, event, handler):
        self._subs[event].append(handler)

    def unsubscribe(self, event, handler):
        if event in self._subs:
            try:
                self._subs[event].remove(handler)
            except ValueError:
                pass  # handler wasn't registered — no-op

    def publish(self, event, *args, **kwargs):
        first_exc = None
        for h in list(self._subs.get(event, [])):  # snapshot in case a handler mutates subs
            try:
                h(*args, **kwargs)
            except Exception as e:
                if first_exc is None:
                    first_exc = e
        if first_exc is not None:
            raise first_exc

class StateMachine:
    def __init__(self, initial, transitions):
        self._state = initial
        self._transitions = dict(transitions)

    @property
    def state(self):
        return self._state

    def send(self, event, *args, **kwargs):
        key = (self._state, event)
        if key not in self._transitions:
            raise ValueError(f'no transition from {self._state!r} on {event!r}')
        new_state, action = self._transitions[key]
        result = action(*args, **kwargs) if action is not None else None
        self._state = new_state
        return result

class Pipe:
    def __init__(self, iterable):
        self._it = iter(iterable)

    def map(self, fn):
        return Pipe(fn(x) for x in self._it)

    def filter(self, predicate):
        return Pipe(x for x in self._it if predicate(x))

    def take(self, n):
        def _take():
            for i, x in enumerate(self._it):
                if i >= n:
                    break
                yield x
        return Pipe(_take())

    def to_list(self):
        return list(self._it)

def range_sum_query(nums):
    # prefix[i] = sum of nums[:i] -> O(n) build, O(1) per query
    prefix = [0]
    for x in nums:
        prefix.append(prefix[-1] + x)
    def query(left, right):
        return prefix[right + 1] - prefix[left]
    return query

def length_of_longest_substring(s):
    last = {}      # char -> most recent index
    left = 0       # left edge of the current window
    best = 0
    for right, ch in enumerate(s):
        if ch in last and last[ch] >= left:
            left = last[ch] + 1
        last[ch] = right
        best = max(best, right - left + 1)
    return best

def longest_palindrome(s):
    if not s:
        return ''
    def expand(lo, hi):
        while lo >= 0 and hi < len(s) and s[lo] == s[hi]:
            lo -= 1
            hi += 1
        return lo + 1, hi  # half-open [lo+1, hi)
    best_lo, best_hi = 0, 1
    for i in range(len(s)):
        lo1, hi1 = expand(i, i)        # odd-length center
        lo2, hi2 = expand(i, i + 1)    # even-length center
        if hi1 - lo1 > best_hi - best_lo:
            best_lo, best_hi = lo1, hi1
        if hi2 - lo2 > best_hi - best_lo:
            best_lo, best_hi = lo2, hi2
    return s[best_lo:best_hi]

def two_sum_sorted(nums, target):
    i, j = 0, len(nums) - 1
    while i < j:
        s = nums[i] + nums[j]
        if s == target:
            return (i, j)
        if s < target:
            i += 1
        else:
            j -= 1
    return None

def three_sum_zero(nums):
    nums = sorted(nums)
    n = len(nums)
    out = []
    for i in range(n - 2):
        if i > 0 and nums[i] == nums[i - 1]:
            continue
        if nums[i] > 0:
            break
        j, k = i + 1, n - 1
        while j < k:
            s = nums[i] + nums[j] + nums[k]
            if s == 0:
                out.append((nums[i], nums[j], nums[k]))
                j += 1
                k -= 1
                while j < k and nums[j] == nums[j - 1]:
                    j += 1
                while j < k and nums[k] == nums[k + 1]:
                    k -= 1
            elif s < 0:
                j += 1
            else:
                k -= 1
    return out

def max_subarray_sum(nums):
    if not nums:
        return 0
    best = cur = nums[0]
    for x in nums[1:]:
        cur = max(x, cur + x)
        best = max(best, cur)
    return best

from collections import defaultdict

def longest_at_most_k_distinct(s, k):
    if not s or k <= 0:
        return 0
    counts = defaultdict(int)
    left = 0
    distinct = 0
    best = 0
    for right, ch in enumerate(s):
        if counts[ch] == 0:
            distinct += 1
        counts[ch] += 1
        while distinct > k:
            counts[s[left]] -= 1
            if counts[s[left]] == 0:
                distinct -= 1
            left += 1
        if right - left + 1 > best:
            best = right - left + 1
    return best

from collections import Counter

def min_window(s, t):
    if not s or not t:
        return ''
    need = Counter(t)
    missing = len(t)
    left = start = end = 0
    for right, ch in enumerate(s, 1):
        if need[ch] > 0:
            missing -= 1
        need[ch] -= 1
        if missing == 0:
            while need[s[left]] < 0:
                need[s[left]] += 1
                left += 1
            if end == 0 or right - left < end - start:
                start, end = left, right
            need[s[left]] += 1
            missing += 1
            left += 1
    return s[start:end]

def stock_span(prices):
    out = []
    stack = []  # (price, span)
    for p in prices:
        span = 1
        while stack and stack[-1][0] <= p:
            span += stack.pop()[1]
        stack.append((p, span))
        out.append(span)
    return out

def next_greater(nums):
    out = [-1] * len(nums)
    stack = []  # indices waiting for their next-greater
    for i, v in enumerate(nums):
        while stack and nums[stack[-1]] < v:
            out[stack.pop()] = v
        stack.append(i)
    return out

def longest_common_prefix(strs):
    if not strs:
        return ''
    s_min = min(strs)
    s_max = max(strs)
    for i, ch in enumerate(s_min):
        if i >= len(s_max) or s_max[i] != ch:
            return s_min[:i]
    return s_min

def is_palindrome_clean(s):
    i, j = 0, len(s) - 1
    while i < j:
        while i < j and not s[i].isalnum():
            i += 1
        while i < j and not s[j].isalnum():
            j -= 1
        if s[i].lower() != s[j].lower():
            return False
        i += 1
        j -= 1
    return True

def edit_distance(a, b):
    m, n = len(a), len(b)
    if m == 0:
        return n
    if n == 0:
        return m
    dp = list(range(n + 1))
    for i in range(1, m + 1):
        prev = dp[0]
        dp[0] = i
        for j in range(1, n + 1):
            cur = dp[j]
            if a[i - 1] == b[j - 1]:
                dp[j] = prev
            else:
                dp[j] = 1 + min(prev, dp[j], dp[j - 1])
            prev = cur
    return dp[n]

def unique_paths(m, n):
    if m <= 0 or n <= 0:
        return 0
    dp = [1] * n
    for _ in range(1, m):
        for j in range(1, n):
            dp[j] += dp[j - 1]
    return dp[-1]

import bisect

def longest_increasing_subseq(nums):
    tails = []  # tails[i] = smallest possible tail of an increasing subseq of length i+1
    for x in nums:
        i = bisect.bisect_left(tails, x)
        if i == len(tails):
            tails.append(x)
        else:
            tails[i] = x
    return len(tails)

def knapsack_01(weights, values, capacity):
    n = len(weights)
    if n == 0 or capacity <= 0:
        return 0
    dp = [0] * (capacity + 1)
    for i in range(n):
        w, v = weights[i], values[i]
        for c in range(capacity, w - 1, -1):
            if dp[c - w] + v > dp[c]:
                dp[c] = dp[c - w] + v
    return dp[capacity]

class DiffArray:
    def __init__(self, n):
        self.n = n
        self.diff = [0] * (n + 1)
    def update(self, i, j, val):
        self.diff[i] += val
        self.diff[j + 1] -= val
    def value_at(self, i):
        total = 0
        for k in range(i + 1):
            total += self.diff[k]
        return total

class RunningStats:
    def __init__(self):
        self.n = 0
        self.mean = 0.0
        self.M2 = 0.0  # sum of squared deviations from the running mean
    def add(self, x):
        self.n += 1
        delta = x - self.mean
        self.mean += delta / self.n
        self.M2 += delta * (x - self.mean)
    def variance(self):
        return self.M2 / self.n if self.n > 0 else 0.0
    def stddev(self):
        return self.variance() ** 0.5

def weighted_average(values, weights):
    if len(values) != len(weights):
        raise ValueError('values and weights must have the same length')
    total_v = 0.0
    total_w = 0.0
    for v, w in zip(values, weights):
        if v is None or w is None:
            continue
        total_v += v * w
        total_w += w
    if total_w == 0:
        return None
    return total_v / total_w

def trimmed_mean(values, trim_pct):
    if not values:
        return 0.0
    n = len(values)
    k = int(n * trim_pct)
    if 2 * k >= n:
        return 0.0
    s = sorted(values)
    keep = s[k:n - k]
    return sum(keep) / len(keep)

def detect_outliers(values, z_threshold=3.0):
    n = len(values)
    if n < 2:
        return []
    mean = sum(values) / n
    var = sum((x - mean) ** 2 for x in values) / n
    std = var ** 0.5
    if std == 0:
        return []
    return [i for i, x in enumerate(values) if abs((x - mean) / std) > z_threshold]

def generate_parens(n):
    if n < 0:
        return []
    if n == 0:
        return ['']
    out = []
    def gen(current, open_count, close_count):
        if len(current) == 2 * n:
            out.append(current)
            return
        if open_count < n:
            gen(current + '(', open_count + 1, close_count)
        if close_count < open_count:
            gen(current + ')', open_count, close_count + 1)
    gen('', 0, 0)
    return out

def lca(parents, a, b):
    seen = set()
    cur = a
    while cur is not None:
        seen.add(cur)
        cur = parents.get(cur)
    cur = b
    while cur is not None:
        if cur in seen:
            return cur
        cur = parents.get(cur)
    return None

def is_balanced_tree(root):
    def height(node):
        if node is None:
            return 0
        lh = height(node['left'])
        if lh == -1:
            return -1
        rh = height(node['right'])
        if rh == -1:
            return -1
        if abs(lh - rh) > 1:
            return -1
        return 1 + max(lh, rh)
    return height(root) != -1

def has_cycle(succ, start):
    slow = fast = start
    while True:
        if slow not in succ:
            return False
        slow = succ[slow]
        if fast not in succ:
            return False
        fast = succ[fast]
        if fast not in succ:
            return False
        fast = succ[fast]
        if slow == fast:
            return True

def build_tree(edges):
    if not edges:
        raise ValueError('no edges')
    parent = {}
    children_of = {}
    nodes = set()
    for p, c in edges:
        parent[c] = p
        children_of.setdefault(p, []).append(c)
        nodes.add(p)
        nodes.add(c)
    roots = [n for n in nodes if n not in parent]
    if len(roots) != 1:
        raise ValueError(f'expected exactly 1 root, got {len(roots)}: {sorted(roots)}')
    return roots[0], children_of

def iterative_dfs(graph, start):
    visited = set()
    out = []
    stack = [start]
    while stack:
        node = stack.pop()
        if node in visited:
            continue
        visited.add(node)
        out.append(node)
        # Push neighbors in REVERSE-sorted order so the smallest is popped first
        for nb in sorted(graph.get(node, []), reverse=True):
            if nb not in visited:
                stack.append(nb)
    return out

import math

class Shape:
    def area(self):
        raise NotImplementedError

class Circle(Shape):
    def __init__(self, radius):
        self.radius = radius
    def area(self):
        return math.pi * self.radius * self.radius

class Rectangle(Shape):
    def __init__(self, w, h):
        self.w, self.h = w, h
    def area(self):
        return self.w * self.h

class Triangle(Shape):
    def __init__(self, base, height):
        self.base = base
        self.height = height
    def area(self):
        return 0.5 * self.base * self.height

def total_area(shapes):
    return sum(s.area() for s in shapes)

class FileSystemNode:
    def __init__(self, name):
        self.name = name
    def size(self):
        raise NotImplementedError

class File(FileSystemNode):
    def __init__(self, name, size):
        super().__init__(name)
        self._size = size
    def size(self):
        return self._size

class Directory(FileSystemNode):
    def __init__(self, name):
        super().__init__(name)
        self.children = []
    def add(self, child):
        self.children.append(child)
    def size(self):
        return sum(c.size() for c in self.children)

class Config:
    _instance = None
    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._data = {}
        return cls._instance
    def set(self, key, value):
        self._data[key] = value
    def get(self, key, default=None):
        return self._data.get(key, default)

class Handler:
    def __init__(self):
        self._next = None
    def set_next(self, handler):
        self._next = handler
        return handler
    def handle(self, request):
        if self._next:
            return self._next.handle(request)
        return None

class AuthHandler(Handler):
    def handle(self, request):
        if request.get('user') is None:
            return 'auth_failed'
        return super().handle(request)

class RateLimitHandler(Handler):
    def handle(self, request):
        if request.get('rate') == 'over':
            return 'rate_limited'
        return super().handle(request)

class FinalHandler(Handler):
    def handle(self, request):
        return 'ok'

def fetch_all(fetch_page):
    items = []
    cursor = None
    while True:
        page, cursor = fetch_page(cursor)
        items.extend(page)
        if cursor is None:
            return items

import functools

def count_calls(fn):
    @functools.wraps(fn)
    def wrapper(*args, **kwargs):
        wrapper.calls += 1
        return fn(*args, **kwargs)
    wrapper.calls = 0
    return wrapper

import functools

def memoize_with_stats(fn):
    cache = {}
    @functools.wraps(fn)
    def wrapper(*args):
        if args in cache:
            wrapper.hits += 1
            return cache[args]
        wrapper.misses += 1
        result = fn(*args)
        cache[args] = result
        return result
    wrapper.hits = 0
    wrapper.misses = 0
    return wrapper

def curry(fn, arity):
    def collect(args):
        if len(args) >= arity:
            return fn(*args[:arity])
        return lambda *more: collect(args + list(more))
    return lambda *args: collect(list(args))

class BST:
    def __init__(self):
        self.root = None
    def insert(self, value):
        def _insert(node):
            if node is None:
                return {'val': value, 'left': None, 'right': None}
            if value < node['val']:
                node['left'] = _insert(node['left'])
            elif value > node['val']:
                node['right'] = _insert(node['right'])
            # value == node['val']: silently ignore (no duplicate)
            return node
        self.root = _insert(self.root)
    def contains(self, value):
        n = self.root
        while n is not None:
            if value == n['val']:
                return True
            n = n['left'] if value < n['val'] else n['right']
        return False
    def inorder(self):
        out = []
        def visit(n):
            if n is None:
                return
            visit(n['left'])
            out.append(n['val'])
            visit(n['right'])
        visit(self.root)
        return out

def horner_eval(coeffs, x):
    result = 0
    for c in coeffs:
        result = result * x + c
    return result

def eval_postfix(tokens):
    OPS = {
        '+': lambda a, b: a + b,
        '-': lambda a, b: a - b,
        '*': lambda a, b: a * b,
        '/': lambda a, b: int(a / b),  # truncate toward zero
    }
    stack = []
    for tok in tokens:
        if tok in OPS:
            b = stack.pop()
            a = stack.pop()
            stack.append(OPS[tok](a, b))
        else:
            stack.append(int(tok))
    return stack[0]

import time
import functools

def cache_with_ttl(ttl_seconds, clock=time.monotonic):
    def deco(fn):
        store = {}
        @functools.wraps(fn)
        def wrapper(*args):
            now = clock()
            if args in store:
                value, ts = store[args]
                if now - ts <= ttl_seconds:
                    return value
            value = fn(*args)
            store[args] = (value, now)
            return value
        return wrapper
    return deco

from collections import Counter

def sort_by_freq(items):
    c = Counter(items)
    first_seen = {}
    for i, it in enumerate(items):
        if it not in first_seen:
            first_seen[it] = i
    sorted_keys = sorted(c.keys(), key=lambda k: (-c[k], first_seen[k]))
    out = []
    for k in sorted_keys:
        out.extend([k] * c[k])
    return out

def max_water_area(heights):
    if len(heights) < 2:
        return 0
    i, j = 0, len(heights) - 1
    best = 0
    while i < j:
        h = min(heights[i], heights[j])
        area = h * (j - i)
        if area > best:
            best = area
        # Move the SHORTER side inward — it limits the area
        if heights[i] < heights[j]:
            i += 1
        else:
            j -= 1
    return best

def trap_rain(heights):
    if len(heights) < 3:
        return 0
    L, R = 0, len(heights) - 1
    left_max = right_max = 0
    total = 0
    while L < R:
        if heights[L] < heights[R]:
            if heights[L] >= left_max:
                left_max = heights[L]
            else:
                total += left_max - heights[L]
            L += 1
        else:
            if heights[R] >= right_max:
                right_max = heights[R]
            else:
                total += right_max - heights[R]
            R -= 1
    return total

import heapq

def k_closest(points, k):
    if k <= 0 or not points:
        return []
    if k >= len(points):
        return sorted(points, key=lambda p: p[0] * p[0] + p[1] * p[1])
    heap = []
    for p in points:
        d = -(p[0] * p[0] + p[1] * p[1])  # negate -> max-heap behavior on heapq (a min-heap)
        if len(heap) < k:
            heapq.heappush(heap, (d, p))
        else:
            heapq.heappushpop(heap, (d, p))
    result = [p for _, p in heap]
    result.sort(key=lambda p: p[0] * p[0] + p[1] * p[1])
    return result

def longest_consecutive(nums):
    s = set(nums)
    best = 0
    for x in s:
        # Only start counting at run STARTS — avoids the inner loop on each member of a run
        if x - 1 not in s:
            length = 1
            cur = x
            while cur + 1 in s:
                cur += 1
                length += 1
            if length > best:
                best = length
    return best

def dedupe_events(events):
    best = {}
    for e in events:
        key = (e['user_id'], e['event_id'])
        if key not in best or e['ts'] > best[key]['ts']:
            best[key] = e
    return sorted(best.values(), key=lambda e: (e['user_id'], e['event_id']))

def parse_money(s):
    s = s.strip()
    if not s:
        return None
    negative = s.startswith('(') and s.endswith(')')
    s = s.strip('()').replace('$', '').replace(',', '').strip()
    if not s:
        return None
    value = float(s)
    return -value if negative else value

def standardize_country(name):
    key = name.strip().lower().replace('.', '').replace(' ', '')
    aliases = {
        'usa': 'United States', 'us': 'United States', 'unitedstates': 'United States',
        'uk': 'United Kingdom', 'greatbritain': 'United Kingdom', 'unitedkingdom': 'United Kingdom',
        'uae': 'United Arab Emirates', 'unitedarabemirates': 'United Arab Emirates',
    }
    if key in aliases:
        return aliases[key]
    return name.strip().title()

def rfm_segments(customers):
    def score(values, reverse):
        order = sorted(range(len(values)), key=lambda i: (values[i], i), reverse=reverse)
        n = len(values)
        s = [0] * n
        for rank, idx in enumerate(order):
            s[idx] = rank * 4 // n + 1
        return s
    rec = [c['days_since_last_order'] for c in customers]
    freq = [c['order_count'] for c in customers]
    mon = [c['total_spend'] for c in customers]
    r = score(rec, reverse=True)
    f = score(freq, reverse=False)
    m = score(mon, reverse=False)
    out = []
    for i, c in enumerate(customers):
        ri, fi, mi = r[i], f[i], m[i]
        if ri >= 3 and fi >= 3 and mi >= 3:
            seg = 'Champion'
        elif ri <= 2 and fi >= 3:
            seg = 'At Risk'
        elif ri >= 3 and fi <= 2:
            seg = 'New'
        else:
            seg = 'Regular'
        out.append({'customer_id': c['customer_id'], 'r': ri, 'f': fi, 'm': mi, 'segment': seg})
    return sorted(out, key=lambda x: x['customer_id'])

def assign_tier(user):
    spend = user['total_spend']
    idle = user['days_since_active']
    if spend >= 1000 and idle <= 30:
        return 'whale'
    if idle > 90:
        return 'dormant'
    if spend >= 100 and idle <= 30:
        return 'core'
    return 'casual'

from datetime import date, timedelta

def make_churn_label(activity, cutoff, horizon_days):
    cut = date.fromisoformat(cutoff)
    horizon_end = cut + timedelta(days=horizon_days)
    pre_users = set()
    active_in_window = set()
    for user_id, d in activity:
        dd = date.fromisoformat(d)
        if dd <= cut:
            pre_users.add(user_id)
        if cut < dd <= horizon_end:
            active_in_window.add(user_id)
    return {u: (0 if u in active_in_window else 1) for u in pre_users}

def growth_accounting(periods, active_by_period):
    out = []
    seen = set()
    prev = set()
    for i, p in enumerate(periods):
        cur = active_by_period.get(p, set())
        if i == 0:
            row = {'period': p, 'active': len(cur), 'new': len(cur),
                   'retained': 0, 'resurrected': 0, 'churned': 0}
        else:
            new = {u for u in cur if u not in seen}
            retained = cur & prev
            resurrected = {u for u in cur if u in seen and u not in prev}
            churned = prev - cur
            row = {'period': p, 'active': len(cur), 'new': len(new),
                   'retained': len(retained), 'resurrected': len(resurrected),
                   'churned': len(churned)}
        out.append(row)
        seen |= cur
        prev = cur
    return out

CREATE TABLE account (
  account_id        BIGSERIAL    PRIMARY KEY,
  external_ref      VARCHAR(64)  NOT NULL UNIQUE,             -- e.g., user-wallet ID or system-account name
  account_type      VARCHAR(16)  NOT NULL,                    -- 'asset','liability','revenue','expense','equity'
  currency          CHAR(3)      NOT NULL,
  is_active         BOOLEAN      NOT NULL DEFAULT TRUE,
  created_at        TIMESTAMPTZ  NOT NULL DEFAULT now()
);

CREATE TABLE transaction (
  transaction_id    BIGSERIAL    PRIMARY KEY,
  external_ref      VARCHAR(64)  NOT NULL UNIQUE,             -- idempotency key from upstream
  description       TEXT,
  occurred_at       TIMESTAMPTZ  NOT NULL,                    -- business time
  recorded_at       TIMESTAMPTZ  NOT NULL DEFAULT now(),      -- system time
  status            VARCHAR(16)  NOT NULL DEFAULT 'posted',   -- 'posted','reversed'
  reversed_by_txn_id BIGINT      REFERENCES transaction(transaction_id)
);

CREATE TABLE ledger_entry (
  entry_id          BIGSERIAL    PRIMARY KEY,
  transaction_id    BIGINT       NOT NULL REFERENCES transaction(transaction_id) ON DELETE RESTRICT,
  account_id        BIGINT       NOT NULL REFERENCES account(account_id),
  direction         CHAR(1)      NOT NULL CHECK (direction IN ('D','C')),
  amount_cents      BIGINT       NOT NULL CHECK (amount_cents > 0),
  currency          CHAR(3)      NOT NULL,
  created_at        TIMESTAMPTZ  NOT NULL DEFAULT now()
);
CREATE INDEX ix_ledger_entry_txn ON ledger_entry (transaction_id);
CREATE INDEX ix_ledger_entry_account_time ON ledger_entry (account_id, created_at);

-- Enforce zero-sum per transaction using a deferred constraint trigger.
CREATE OR REPLACE FUNCTION assert_ledger_balanced() RETURNS trigger AS $$
DECLARE
  imbalance NUMERIC;
BEGIN
  SELECT
    SUM(CASE WHEN direction = 'D' THEN amount_cents ELSE -amount_cents END)
    INTO imbalance
  FROM ledger_entry
  WHERE transaction_id = NEW.transaction_id;
  IF imbalance IS NULL OR imbalance <> 0 THEN
    RAISE EXCEPTION 'Ledger entries for transaction % do not balance: %', NEW.transaction_id, imbalance;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE CONSTRAINT TRIGGER trg_ledger_balanced
  AFTER INSERT OR UPDATE OR DELETE ON ledger_entry
  DEFERRABLE INITIALLY DEFERRED
  FOR EACH ROW EXECUTE FUNCTION assert_ledger_balanced();

-- Reversal pattern: insert a NEW transaction (status='posted') whose entries are the inverse of the
-- original (debits become credits and vice versa), and set the original.status = 'reversed' and
-- original.reversed_by_txn_id = new_txn_id.

CREATE TABLE comment (
  comment_id        BIGSERIAL    PRIMARY KEY,
  post_id           BIGINT       NOT NULL,
  parent_comment_id BIGINT       REFERENCES comment(comment_id),
  author_id         BIGINT       NOT NULL,
  body              TEXT         NOT NULL,
